function vendreProduit(nom, qteVendue) {
  for (let i = 0; i < stock.length; i++) {
    if (stock[i].nom === nom) {
      if (stock[i].quantite >= qteVendue) {
        stock[i].quantite -= qteVendue;
        console.log(`Vente effectuée. Nouveau stock de ${nom} : ${stock[i].quantite}`);
      } else {
        console.log(`Stock insuffisant ! Il reste ${stock[i].quantite} ${nom}`);
      }
      return;
    }
  }
  console.log('Produit non trouvé');
}

function valeurTotaleStock() {
  let total = 0;
  for (let i = 0; i < stock.length; i++) {
    total += stock[i].quantite * stock[i].prix;
  }
  return total;
}
